import React, { useState } from 'react';
import { parseCV } from '../services/api';

function CVUpload({ onSkillsExtracted }) {
  const [file, setFile] = useState(null);
  const [skills, setSkills] = useState([]);
  const [manualInput, setManualInput] = useState('');

  const handleFileChange = (e) => {
    setFile(e.target.files[0]);
  };

  const handleManualSubmit = async () => {
    if (!manualInput.trim()) return;
    const extractedSkills = await parseCV(manualInput);
    setSkills(extractedSkills);
    onSkillsExtracted(extractedSkills);
  };

  const handleFileSubmit = async () => {
    if (!file) return;

    // In a real app, you would read the file and extract text
    // For simplicity, we'll assume we have the text
    const cvText = "This is a sample CV text with skills like JavaScript, React, Node.js, etc.";
    const extractedSkills = await parseCV(cvText);
    setSkills(extractedSkills);
    onSkillsExtracted(extractedSkills);
  };

  return (
    <div className="cv-upload">
      <h2>Upload CV or Enter Skills Manually</h2>

      <div className="file-upload">
        <input type="file" accept=".pdf" onChange={handleFileChange} />
        <button onClick={handleFileSubmit}>Parse CV</button>
      </div>

      <div className="manual-input">
        <textarea 
          value={manualInput} 
          onChange={(e) => setManualInput(e.target.value)} 
          placeholder="Paste your CV text or list your skills here..."
        />
        <button onClick={handleManualSubmit}>Submit</button>
      </div>

      {skills.length > 0 && (
        <div className="skills-list">
          <h3>Extracted Skills:</h3>
          <ul>
            {skills.map((skill, i) => <li key={i}>{skill}</li>)}
          </ul>
        </div>
      )}
    </div>
  );
}

export default CVUpload;
